"""
ValuMetrics AI — Generador de Informe Pericial PDF
===================================================
Produce un informe profesional de tasación en formato A4,
con portada, desglose técnico, tabla de cálculos y firma pericial.
Usa ReportLab (sin wkhtmltopdf para evitar crash por logo PNG).
"""

import io
import base64
from datetime import datetime
from reportlab.platypus import Image as RLImage

# Logo embebido (JPEG en base64 — evita crash por PNG transparente)
_LOGO_B64 = ""
_LOGO_BYTES = base64.b64decode(_LOGO_B64)

from typing import Optional
from reportlab.lib.pagesizes import A4
from reportlab.lib import colors
from reportlab.lib.units import mm, cm
from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
from reportlab.lib.enums import TA_LEFT, TA_CENTER, TA_RIGHT, TA_JUSTIFY
from reportlab.platypus import (
    SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle,
    HRFlowable, PageBreak, KeepTogether
)
from reportlab.platypus.flowables import HRFlowable
from reportlab.lib.colors import HexColor, white, black

# ──────────────────────────────────────────────────────
#  Paleta ValuMetrics AI
# ──────────────────────────────────────────────────────
AZUL_REY   = HexColor("#0C2340")
ROJO_DIA   = HexColor("#C8102E")
AZUL_CLARO = HexColor("#1E4080")
GRIS_OSC   = HexColor("#2C3E50")
GRIS_MED   = HexColor("#95A5A6")
GRIS_FONDO = HexColor("#F4F6F9")
VERDE_OK   = HexColor("#27AE60")
AMARILLO   = HexColor("#F39C12")

W, H = A4  # 210 × 297 mm

# ──────────────────────────────────────────────────────
#  Helpers de formato
# ──────────────────────────────────────────────────────

def fmt_usd(v: float) -> str:
    return f"$ {v:,.2f} USD"

def fmt_ves(v: float) -> str:
    return f"{v:,.0f} VES"

def fmt_pct(v: float) -> str:
    return f"{v * 100:.2f}%"

def fmt_score(v: float) -> str:
    return f"{v:.1f}%"

def confidence_label(score: float) -> str:
    if score >= 75: return "Alta"
    if score >= 50: return "Media"
    return "Baja"

def tipo_label(tipo: str) -> str:
    labels = {
        "propiedad_horizontal": "Propiedad Horizontal (Apartamento)",
        "vivienda_familiar":    "Vivienda Familiar (Casa/Quinta)",
        "local_comercial":      "Local Comercial / Oficina",
        "galpon_industrial":    "Galpón Industrial / Nave",
        "terreno":              "Terreno / Parcela",
        "finca":                "Finca / Hacienda / Fundo",
    }
    return labels.get(tipo, tipo.replace("_", " ").title())


# ──────────────────────────────────────────────────────
#  Estilos
# ──────────────────────────────────────────────────────

def build_styles():
    base = getSampleStyleSheet()

    styles = {}

    styles["portada_titulo"] = ParagraphStyle(
        "portada_titulo",
        fontName="Helvetica-Bold",
        fontSize=26,
        textColor=white,
        alignment=TA_CENTER,
        spaceAfter=4,
        leading=30,
    )
    styles["portada_sub"] = ParagraphStyle(
        "portada_sub",
        fontName="Helvetica",
        fontSize=11,
        textColor=HexColor("#BDC3C7"),
        alignment=TA_CENTER,
        spaceAfter=2,
    )
    styles["portada_valor"] = ParagraphStyle(
        "portada_valor",
        fontName="Helvetica-Bold",
        fontSize=34,
        textColor=ROJO_DIA,
        alignment=TA_CENTER,
        spaceAfter=2,
    )
    styles["portada_ves"] = ParagraphStyle(
        "portada_ves",
        fontName="Helvetica",
        fontSize=14,
        textColor=HexColor("#ECF0F1"),
        alignment=TA_CENTER,
        spaceAfter=6,
    )
    styles["seccion_titulo"] = ParagraphStyle(
        "seccion_titulo",
        fontName="Helvetica-Bold",
        fontSize=13,
        textColor=AZUL_REY,
        spaceBefore=14,
        spaceAfter=6,
        borderPad=4,
    )
    styles["campo_label"] = ParagraphStyle(
        "campo_label",
        fontName="Helvetica-Bold",
        fontSize=9,
        textColor=GRIS_OSC,
    )
    styles["campo_valor"] = ParagraphStyle(
        "campo_valor",
        fontName="Helvetica",
        fontSize=9,
        textColor=GRIS_OSC,
    )
    styles["nota"] = ParagraphStyle(
        "nota",
        fontName="Helvetica-Oblique",
        fontSize=8,
        textColor=GRIS_MED,
        spaceAfter=3,
    )
    styles["hash"] = ParagraphStyle(
        "hash",
        fontName="Courier",
        fontSize=8,
        textColor=GRIS_MED,
        alignment=TA_CENTER,
    )
    styles["firma_nombre"] = ParagraphStyle(
        "firma_nombre",
        fontName="Helvetica-Bold",
        fontSize=10,
        textColor=AZUL_REY,
        alignment=TA_CENTER,
    )
    styles["firma_cargo"] = ParagraphStyle(
        "firma_cargo",
        fontName="Helvetica",
        fontSize=9,
        textColor=GRIS_MED,
        alignment=TA_CENTER,
    )
    styles["disclaimer"] = ParagraphStyle(
        "disclaimer",
        fontName="Helvetica",
        fontSize=7,
        textColor=GRIS_MED,
        alignment=TA_JUSTIFY,
        leading=10,
    )
    styles["valor_grande"] = ParagraphStyle(
        "valor_grande",
        fontName="Helvetica-Bold",
        fontSize=20,
        textColor=ROJO_DIA,
        alignment=TA_CENTER,
    )
    return styles


# ──────────────────────────────────────────────────────
#  Cabecera de página (canvas callback)
# ──────────────────────────────────────────────────────

def header_footer(canvas, doc):
    canvas.saveState()
    # Línea roja superior
    canvas.setFillColor(ROJO_DIA)
    canvas.rect(0, H - 8*mm, W, 8*mm, fill=1, stroke=0)
    # Nombre empresa en cabecera
    canvas.setFont("Helvetica-Bold", 9)
    canvas.setFillColor(white)
    canvas.drawString(20*mm, H - 5.5*mm, "ValuMetrics AI  |  Inteligencia Inmobiliaria Avanzada")
    # Número de página
    canvas.drawRightString(W - 20*mm, H - 5.5*mm, f"Página {doc.page}")

    # Pie de página
    canvas.setFillColor(AZUL_REY)
    canvas.rect(0, 0, W, 10*mm, fill=1, stroke=0)
    canvas.setFont("Helvetica", 7)
    canvas.setFillColor(white)
    canvas.drawString(20*mm, 3.5*mm, "© 2025 ValuMetrics AI  |  Informe generado electrónicamente  |  valumetricsai.vercel.app")
    canvas.drawRightString(W - 20*mm, 3.5*mm, "CONFIDENCIAL — USO EXCLUSIVO DEL SOLICITANTE")

    canvas.restoreState()


# ──────────────────────────────────────────────────────
#  Función principal
# ──────────────────────────────────────────────────────

def generar_informe_pdf(resultado, nombre_perito: str = "ValuMetrics AI Engine") -> bytes:
    buffer = io.BytesIO()
    r = resultado
    S = build_styles()

    doc = SimpleDocTemplate(
        buffer,
        pagesize=A4,
        leftMargin=20*mm,
        rightMargin=20*mm,
        topMargin=20*mm,
        bottomMargin=18*mm,
        title=f"Informe Pericial - {r.hash_operacion}",
        author="ValuMetrics AI",
    )

    story = []

    # ══════════════════════════════════════════
    #  PORTADA
    # ══════════════════════════════════════════

    # Logo institucional
    import io as _io
    logo_buf = _io.BytesIO(_LOGO_BYTES)
    logo_img = RLImage(logo_buf, width=55*mm, height=55*mm)
    logo_img.hAlign = 'CENTER'
    story.append(logo_img)
    story.append(Spacer(1, 4*mm))

    # Bloque azul de portada (tabla de 1 celda con fondo)
    portada_data = [[
        Paragraph("INFORME TÉCNICO DE VALORACIÓN INMOBILIARIA", S["portada_titulo"]),
    ]]
    portada_tabla = Table(portada_data, colWidths=[W - 40*mm])
    portada_tabla.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, -1), AZUL_REY),
        ("TOPPADDING",    (0, 0), (-1, -1), 28),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 18),
        ("LEFTPADDING",   (0, 0), (-1, -1), 16),
        ("RIGHTPADDING",  (0, 0), (-1, -1), 16),
        ("ROUNDEDCORNERS", [6]),
    ]))
    story.append(portada_tabla)
    story.append(Spacer(1, 10*mm))

    # Subtítulo tipo inmueble
    story.append(Paragraph(tipo_label(r.tipo_inmueble).upper(), S["portada_sub"]))
    story.append(Paragraph(r.direccion, S["portada_sub"]))
    story.append(Spacer(1, 8*mm))

    # Valor principal
    valor_data = [[
        Paragraph("VALOR DE MERCADO ESTIMADO", S["portada_sub"]),
    ], [
        Paragraph(fmt_usd(r.valor_total_usd), S["portada_valor"]),
    ], [
        Paragraph(fmt_ves(r.valor_total_ves), S["portada_ves"]),
    ]]
    valor_tabla = Table(valor_data, colWidths=[W - 40*mm])
    valor_tabla.setStyle(TableStyle([
        ("BACKGROUND",    (0, 0), (-1, -1), AZUL_REY),
        ("TOPPADDING",    (0, 0), (-1, -1), 12),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 12),
        ("LEFTPADDING",   (0, 0), (-1, -1), 16),
        ("RIGHTPADDING",  (0, 0), (-1, -1), 16),
        ("ALIGN",         (0, 0), (-1, -1), "CENTER"),
        ("ROUNDEDCORNERS", [6]),
    ]))
    story.append(valor_tabla)
    story.append(Spacer(1, 6*mm))

    # Meta info en portada
    meta_fecha = datetime.fromisoformat(r.timestamp).strftime("%d/%m/%Y  %H:%M")
    meta_data = [
        ["ID de Operación",  r.hash_operacion,    "Fecha del Análisis", meta_fecha],
        ["Metodología",      "Ross-Heidecke",      "Score de Confianza", fmt_score(r.confidence_score)],
        ["Tasa BCV",         f"{r.tasa_bcv:,.0f} VES/USD", "Delta Geográfico", r.delta_geografico],
    ]
    meta_tabla = Table(meta_data, colWidths=[42*mm, 58*mm, 42*mm, 28*mm])
    meta_tabla.setStyle(TableStyle([
        ("FONTNAME",      (0, 0), (-1, -1), "Helvetica"),
        ("FONTNAME",      (0, 0), (0, -1), "Helvetica-Bold"),
        ("FONTNAME",      (2, 0), (2, -1), "Helvetica-Bold"),
        ("FONTSIZE",      (0, 0), (-1, -1), 8),
        ("TEXTCOLOR",     (0, 0), (0, -1), AZUL_REY),
        ("TEXTCOLOR",     (2, 0), (2, -1), AZUL_REY),
        ("ROWBACKGROUNDS",(0, 0), (-1, -1), [GRIS_FONDO, white]),
        ("GRID",          (0, 0), (-1, -1), 0.5, HexColor("#DDE1E7")),
        ("TOPPADDING",    (0, 0), (-1, -1), 5),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 5),
        ("LEFTPADDING",   (0, 0), (-1, -1), 6),
    ]))
    story.append(meta_tabla)
    story.append(PageBreak())

    # ══════════════════════════════════════════
    #  SECCIÓN 1: DESCRIPCIÓN DEL INMUEBLE
    # ══════════════════════════════════════════

    story.append(Paragraph("1. DESCRIPCIÓN DEL INMUEBLE", S["seccion_titulo"]))
    story.append(HRFlowable(width="100%", thickness=1.5, color=ROJO_DIA, spaceAfter=6))

    p = resultado.parametros_entrada
    techo_labels = {
        "losa_maciza":"Losa Maciza","losa_nervada":"Losa Nervada","losa_prefabricada":"Losa Prefabricada",
        "acerolit":"Acerolit","zinc_galvanizado":"Zinc Galvanizado","zinc_prepintado":"Zinc Prepintado",
        "teja_ceramica":"Teja Cerámica","machihembrado":"Machihembrado","madera_rustica":"Madera Rústica",
        "platabanda":"Platabanda","mixto_techo":"Mixto",
    }
    clima_labels = {"centralizado":"A/C Centralizado","individual":"A/C Individual","ventilacion":"Ventilación Natural","ninguno":"Sin A/C"}
    amenidades = p.get("amenidades") or []
    am_str = ", ".join([a.replace("_"," ").title() for a in amenidades]) if amenidades else "—"

    # Helper para valores del PDF — evita None y cadenas vacías
    def gv(key, default="—"):
        v = p.get(key, default)
        if v is None or v == "" or v == [] or v == 0:
            return default
        return v
    def gn(key, default=0):
        try: return float(p.get(key, default) or default)
        except: return default

    zona_str = (gv("zona_clase","") + " · " + gv("zona_tipo","")).strip(" ·") or "—"
    zona_str = zona_str.replace("_", " ").title()

    desc_rows = [
        ["Tipo de Inmueble",       tipo_label(r.tipo_inmueble),
         "Estado de Conservación", (gv("estado_conservacion") or "normal").title()],
        ["Dirección",              r.direccion or "—",
         "Ciudad",                 gv("ciudad")],
        ["Zona / Clasificación",   zona_str,
         "Tipo Construcción",      gv("tipo_construccion","—").replace("_", " ").title()],
        ["Tipo de Techo",          techo_labels.get(p.get("tipo_techo",""), gv("tipo_techo")),
         "Climatización",          clima_labels.get(p.get("clima",""), gv("clima"))],
        ["Acabados",               gv("acabados","—").replace("_", " ").title(),
         "Edad Estructural",       f"{gn('edad_anios'):.0f} años"],
        ["Área de Terreno",        f"{gn('area_terreno_m2'):,.2f} m²",
         "Área Construida",        f"{gn('area_construida_m2'):,.2f} m²"],
        ["Habitaciones",           str(int(gn('habitaciones'))) if gn('habitaciones') else "—",
         "Baños / Medios",         f"{int(gn('banos'))} baños + {int(gn('medios_banos'))} medios" if (gn('banos') or gn('medios_banos')) else "—"],
        ["Estacionamientos",       str(int(gn('estacionamientos') or gn('puesto_estacionamiento'))) if (gn('estacionamientos') or gn('puesto_estacionamiento')) else "—",
         "Amenidades",             (am_str[:60] + ("…" if len(am_str)>60 else "")) if am_str != "—" else "—"],
    ]

    # Filas adicionales por tipo
    tipo = r.tipo_inmueble
    if tipo == "propiedad_horizontal":
        desc_rows.append([
            "Piso / Nivel",            str(int(gn("piso_nivel",1))),
            "Estacionamientos",        str(int(gn("puesto_estacionamiento") or gn("estacionamientos"))),
        ])
        desc_rows.append([
            "Ascensor",                "Sí" if p.get("tiene_ascensor") else "No",
            "Tipo de Techo",           techo_labels.get(p.get("tipo_techo",""), gv("tipo_techo")),
        ])
    elif tipo == "vivienda_familiar":
        desc_rows.append([
            "Tipo de Techo",           techo_labels.get(p.get("tipo_techo",""), gv("tipo_techo")),
            "Estacionamientos",        str(int(gn("estacionamientos") or gn("puesto_estacionamiento"))),
        ])
    elif tipo == "galpon_industrial":
        desc_rows.append([
            "Altura Libre",            f"{gn('altura_libre_m'):.1f} m" if gn('altura_libre_m') else "—",
            "Cap. Eléctrica",          f"{gn('capacidad_electrica_kva'):.0f} kVA" if gn('capacidad_electrica_kva') else "—",
        ])
        galpon_feats = p.get("caract_galpon") or []
        if galpon_feats:
            desc_rows.append([
                "Características",     ", ".join([g.replace("_"," ").title() for g in galpon_feats[:4]]),
                "", "",
            ])
    elif tipo == "finca":
        desc_rows.append([
            "Hectáreas Totales",       f"{gn('hectareas'):.2f} ha" if gn('hectareas') else "—",
            "Vocación",                gv("vocacion","—").replace("_"," ").title(),
        ])
        desc_rows.append([
            "Acceso al Agua",          gv("agua_finca","—").replace("_"," ").title(),
            "Topografía",              gv("topografia","—").replace("_"," ").title(),
        ])
    elif tipo == "local_comercial":
        desc_rows.append([
            "Subtipo",                 gv("subtipo_local","—").replace("_"," ").title(),
            "Visibilidad",             gv("visibilidad","—").replace("_"," ").title(),
        ])
    elif tipo == "terreno":
        desc_rows.append([
            "Clasificación",           gv("clase_terreno","—").replace("_"," ").title(),
            "Frente × Fondo",          f"{gn('frente_terreno'):.0f}m × {gn('fondo_terreno'):.0f}m" if gn('frente_terreno') else "—",
        ])
        desc_rows.append([
            "Topografía",              gv("topo_terreno","—").replace("_"," ").title(),
            "Tipo de Suelo",           gv("suelo_terreno","—").replace("_"," ").title(),
        ])

    desc_tabla = Table(desc_rows, colWidths=[42*mm, 58*mm, 42*mm, 28*mm])
    desc_tabla.setStyle(TableStyle([
        ("FONTNAME",      (0, 0), (-1, -1), "Helvetica"),
        ("FONTNAME",      (0, 0), (0, -1), "Helvetica-Bold"),
        ("FONTNAME",      (2, 0), (2, -1), "Helvetica-Bold"),
        ("FONTSIZE",      (0, 0), (-1, -1), 8.5),
        ("TEXTCOLOR",     (0, 0), (0, -1), AZUL_REY),
        ("TEXTCOLOR",     (2, 0), (2, -1), AZUL_REY),
        ("ROWBACKGROUNDS",(0, 0), (-1, -1), [GRIS_FONDO, white]),
        ("GRID",          (0, 0), (-1, -1), 0.4, HexColor("#DDE1E7")),
        ("TOPPADDING",    (0, 0), (-1, -1), 5),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 5),
        ("LEFTPADDING",   (0, 0), (-1, -1), 6),
    ]))
    story.append(desc_tabla)
    story.append(Spacer(1, 6*mm))

    # ══════════════════════════════════════════
    #  SECCIÓN 2: MATRIZ DE CÁLCULO (ROSS-HEIDECKE)
    # ══════════════════════════════════════════

    story.append(Paragraph("2. MATRIZ DE TASACIÓN PREDICTIVA — ROSS-HEIDECKE", S["seccion_titulo"]))
    story.append(HRFlowable(width="100%", thickness=1.5, color=ROJO_DIA, spaceAfter=6))

    calc_rows = [
        # Header
        [
            Paragraph("COMPONENTE", ParagraphStyle("th", fontName="Helvetica-Bold", fontSize=8, textColor=white, alignment=TA_CENTER)),
            Paragraph("DETALLE", ParagraphStyle("th", fontName="Helvetica-Bold", fontSize=8, textColor=white, alignment=TA_CENTER)),
            Paragraph("VALOR (USD)", ParagraphStyle("th", fontName="Helvetica-Bold", fontSize=8, textColor=white, alignment=TA_RIGHT)),
        ],
        ["Valor de Tierra",
         f"{p.get('area_terreno_m2', 0):,.0f} m² × $ {p.get('valor_tierra_usd_m2', 0):,.2f}/m² × Factor Zona {r.factor_zona:.2f}",
         fmt_usd(r.valor_tierra_usd)],
        ["Valor Construcción Nuevo",
         f"{p.get('area_construida_m2', 0):,.0f} m² × Costo Base × Factor Acabados {r.factor_acabados:.2f}",
         fmt_usd(r.valor_construccion_nuevo_usd)],
        ["Depreciación (Ross-Heidecke)",
         f"x = {p.get('edad_anios', 0):.0f} / {r.vida_util_aplicada:.0f} años → D = {fmt_pct(r.depreciacion_rate)}",
         f"- {fmt_usd(r.valor_construccion_nuevo_usd * r.depreciacion_rate)}"],
        ["Valor Construcción Deprecado",
         f"Estado: {r.estado_conservacion.title()}",
         fmt_usd(r.valor_construccion_depreciado_usd)],
    ]

    if r.valor_renta_capitalizado_usd > 0:
        calc_rows.append([
            "Valor por Capitalización Rentas",
            f"Renta ${p.get('renta_mensual_usd', 0):,.0f}/mes / Yield {r.metodologia.split('+')[-1].strip() if '+' in r.metodologia else '—'}",
            fmt_usd(r.valor_renta_capitalizado_usd),
        ])

    # Fila total
    calc_rows.append([
        Paragraph("VALOR TOTAL ESTIMADO", ParagraphStyle("tot", fontName="Helvetica-Bold", fontSize=10, textColor=white)),
        Paragraph(r.metodologia, ParagraphStyle("met", fontName="Helvetica-Oblique", fontSize=7.5, textColor=HexColor("#BDC3C7"))),
        Paragraph(fmt_usd(r.valor_total_usd), ParagraphStyle("totv", fontName="Helvetica-Bold", fontSize=11, textColor=ROJO_DIA, alignment=TA_RIGHT)),
    ])

    calc_tabla = Table(calc_rows, colWidths=[50*mm, 80*mm, 40*mm])
    n = len(calc_rows)
    calc_tabla.setStyle(TableStyle([
        # Header
        ("BACKGROUND",    (0, 0), (-1, 0), AZUL_REY),
        ("TEXTCOLOR",     (0, 0), (-1, 0), white),
        ("FONTNAME",      (0, 0), (-1, 0), "Helvetica-Bold"),
        ("FONTSIZE",      (0, 0), (-1, 0), 8),
        # Body
        ("FONTNAME",      (0, 1), (-1, -2), "Helvetica"),
        ("FONTSIZE",      (0, 1), (-1, -2), 8.5),
        ("ROWBACKGROUNDS",(0, 1), (-1, -2), [GRIS_FONDO, white]),
        # Total row
        ("BACKGROUND",    (0, n-1), (-1, n-1), AZUL_REY),
        ("FONTNAME",      (0, n-1), (-1, n-1), "Helvetica-Bold"),
        # Alignment
        ("ALIGN",         (2, 0), (2, -1), "RIGHT"),
        ("GRID",          (0, 0), (-1, -1), 0.4, HexColor("#DDE1E7")),
        ("TOPPADDING",    (0, 0), (-1, -1), 6),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 6),
        ("LEFTPADDING",   (0, 0), (-1, -1), 6),
    ]))
    story.append(calc_tabla)
    story.append(Spacer(1, 6*mm))

    # ══════════════════════════════════════════
    #  SECCIÓN 3: INDICADORES ANALÍTICOS
    # ══════════════════════════════════════════

    story.append(Paragraph("3. INDICADORES ANALÍTICOS", S["seccion_titulo"]))
    story.append(HRFlowable(width="100%", thickness=1.5, color=ROJO_DIA, spaceAfter=6))

    zona_factor_str = f"× {r.factor_zona:.2f}"
    if r.score_zona:
        zona_factor_str += f"  (Score {r.score_zona}/100)"

    fp  = getattr(r, 'factor_pais',   1.0)
    fc  = getattr(r, 'factor_ciudad', 1.0)
    rp  = getattr(r, 'riesgo_pais_aplicado', p.get('pais','—'))
    fm  = round(fp*0.70 + fc*0.30, 3)

    riesgo_label = "Bajo" if fp>=0.85 else "Medio" if fp>=0.65 else "Alto" if fp>=0.40 else "Muy Alto"

    ind_rows = [
        ["Valor por m² construido",    fmt_usd(r.valor_por_m2_usd),
         "Score de Confianza",         f"{fmt_score(r.confidence_score)} — {confidence_label(r.confidence_score)}"],
        ["Depreciación Aplicada",      fmt_pct(r.depreciacion_rate),
         "Delta Geográfico",           r.delta_geografico],
        ["Vida Útil Normativa",        f"{r.vida_util_aplicada:.0f} años",
         "Factor de Zona",             zona_factor_str],
        ["Tasa BCV Aplicada",          f"{r.tasa_bcv:,.0f} VES / USD",
         "Factor Acabados",            f"× {r.factor_acabados:.2f}"],
        ["Riesgo País",                f"× {fp:.3f} ({riesgo_label}) — {rp.title()}",
         "Factor Ciudad/Jerarquía",    f"× {fc:.3f}"],
        ["Factor Macro Aplicado",      f"× {fm:.3f}  (País 70% + Ciudad 30%)",
         "", ""],
        ["Valor Total VES",            fmt_ves(r.valor_total_ves),
         "Valor Total USD",            fmt_usd(r.valor_total_usd)],
    ]

    # Si hay desglose de zona avanzado, agregar tabla extra
    if r.desglose_zona:
        story.append(Spacer(1, 4*mm))
        story.append(Paragraph("3b. DESGLOSE DE PUNTUACIÓN DE ZONA", S["seccion_titulo"]))
        story.append(HRFlowable(width="100%", thickness=1, color=ROJO_DIA, spaceAfter=4))
        zona_labels = {
            "clase_zona":"Clase socioeconómica","acceso":"Tipo de comunidad/acceso",
            "vias":"Estado de vías","servicios":"Servicios públicos",
            "equipamiento":"Equipamiento urbano","uso_suelo":"Zonificación oficial",
            "densidad":"Densidad poblacional","ambito":"Ámbito territorial",
            "seguridad":"Seguridad percibida",
        }
        desglose_rows = [[
            Paragraph("FACTOR", ParagraphStyle("zh", fontName="Helvetica-Bold", fontSize=8, textColor=white)),
            Paragraph("PUNTOS", ParagraphStyle("zh2", fontName="Helvetica-Bold", fontSize=8, textColor=white, alignment=1)),
        ]]
        for k, v in r.desglose_zona.items():
            desglose_rows.append([zona_labels.get(k, k), str(v)])
        desglose_rows.append([
            Paragraph("TOTAL SCORE", ParagraphStyle("zt", fontName="Helvetica-Bold", fontSize=9, textColor=white)),
            Paragraph(f"{r.score_zona}/100  →  Factor ×{r.factor_zona:.2f}", ParagraphStyle("ztv", fontName="Helvetica-Bold", fontSize=9, textColor=ROJO_DIA)),
        ])
        dz_tabla = Table(desglose_rows, colWidths=[120*mm, 50*mm])
        dz_tabla.setStyle(TableStyle([
            ("BACKGROUND",    (0,0),(-1,0), AZUL_REY),
            ("BACKGROUND",    (0,-1),(-1,-1), AZUL_REY),
            ("ROWBACKGROUNDS",(0,1),(-1,-2), [GRIS_FONDO, white]),
            ("FONTSIZE",      (0,1),(-1,-2), 8.5),
            ("FONTNAME",      (0,1),(-1,-2), "Helvetica"),
            ("ALIGN",         (1,0),(1,-1), "CENTER"),
            ("GRID",          (0,0),(-1,-1), 0.4, HexColor("#DDE1E7")),
            ("TOPPADDING",    (0,0),(-1,-1), 5),
            ("BOTTOMPADDING", (0,0),(-1,-1), 5),
            ("LEFTPADDING",   (0,0),(-1,-1), 8),
        ]))
        story.append(dz_tabla)
    ind_tabla = Table(ind_rows, colWidths=[42*mm, 58*mm, 42*mm, 28*mm])
    ind_tabla.setStyle(TableStyle([
        ("FONTNAME",      (0, 0), (-1, -1), "Helvetica"),
        ("FONTNAME",      (0, 0), (0, -1), "Helvetica-Bold"),
        ("FONTNAME",      (2, 0), (2, -1), "Helvetica-Bold"),
        ("FONTSIZE",      (0, 0), (-1, -1), 8.5),
        ("TEXTCOLOR",     (0, 0), (0, -1), AZUL_REY),
        ("TEXTCOLOR",     (2, 0), (2, -1), AZUL_REY),
        # Highlight valor total VES
        ("BACKGROUND",    (0, 4), (-1, 4), AZUL_REY),
        ("TEXTCOLOR",     (0, 4), (-1, 4), white),
        ("FONTNAME",      (0, 4), (-1, 4), "Helvetica-Bold"),
        ("ROWBACKGROUNDS",(0, 0), (-1, 3), [GRIS_FONDO, white]),
        ("GRID",          (0, 0), (-1, -1), 0.4, HexColor("#DDE1E7")),
        ("TOPPADDING",    (0, 0), (-1, -1), 5),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 5),
        ("LEFTPADDING",   (0, 0), (-1, -1), 6),
    ]))
    story.append(ind_tabla)
    story.append(Spacer(1, 6*mm))

    # ══════════════════════════════════════════
    #  SECCIÓN 4: OBSERVACIONES PERICIALES
    # ══════════════════════════════════════════

    story.append(Paragraph("4. OBSERVACIONES Y AJUSTES PERICIALES", S["seccion_titulo"]))
    story.append(HRFlowable(width="100%", thickness=1.5, color=ROJO_DIA, spaceAfter=6))

    if r.notas_pericial:
        for nota in r.notas_pericial:
            story.append(Paragraph(f"• {nota}", S["campo_valor"]))
            story.append(Spacer(1, 2))
    else:
        story.append(Paragraph("No se registraron ajustes especiales adicionales para este tipo de inmueble.", S["campo_valor"]))

    if p.get("notas"):
        story.append(Spacer(1, 4))
        story.append(Paragraph(f"Notas del solicitante: {p['notas']}", S["nota"]))

    story.append(Spacer(1, 8*mm))

    # ══════════════════════════════════════════
    #  SECCIÓN 5: FÓRMULA Y METODOLOGÍA
    # ══════════════════════════════════════════

    story.append(Paragraph("5. FÓRMULA Y FUNDAMENTO MATEMÁTICO", S["seccion_titulo"]))
    story.append(HRFlowable(width="100%", thickness=1.5, color=ROJO_DIA, spaceAfter=6))

    formula_text = (
        "<b>Fórmula de Depreciación Röss-Hödecke:</b><br/>"
        "D = 0.5 × (x + x<super>2</super>)   donde   x = Edad / Vida Útil<br/><br/>"
        f"Para este inmueble:  x = {p.get('edad_anios', 0):.0f} / {r.vida_util_aplicada:.0f} = "
        f"{p.get('edad_anios', 0)/r.vida_util_aplicada:.4f}  →  D = {fmt_pct(r.depreciacion_rate)}<br/><br/>"
        "<b>Valor de Mercado (método costo):</b><br/>"
        "V<sub>m</sub> = V<sub>tierra</sub> + V<sub>construccion</sub> × (1 – D) × F<sub>zona</sub> × F<sub>acabados</sub><br/><br/>"
    )
    if r.valor_renta_capitalizado_usd > 0:
        formula_text += (
            "<b>Capitalización de Rentas (ponderación 40%):</b><br/>"
            "V<sub>renta</sub> = Renta Anual / Yield<br/>"
            "V<sub>final</sub> = V<sub>fisico</sub> × 60% + V<sub>renta</sub> × 40%<br/>"
        )

    story.append(Paragraph(formula_text, ParagraphStyle(
        "formula", fontName="Helvetica", fontSize=9, textColor=GRIS_OSC,
        leading=14, spaceAfter=4
    )))
    story.append(Spacer(1, 6*mm))

    # ══════════════════════════════════════════
    #  FIRMA PERICIAL
    # ══════════════════════════════════════════

    story.append(Spacer(1, 10*mm))
    firma_data = [[
        Paragraph("____________________________", S["firma_nombre"]),
        "",
        Paragraph("____________________________", S["firma_nombre"]),
    ], [
        Paragraph(nombre_perito or "ValuMetrics AI Engine", S["firma_nombre"]),
        "",
        Paragraph("Responsable del Inmueble", S["firma_nombre"]),
    ], [
        Paragraph("Perito Valuador Certificado", S["firma_cargo"]),
        "",
        Paragraph("Firma y Sello del Propietario", S["firma_cargo"]),
    ]]
    firma_tabla = Table(firma_data, colWidths=[70*mm, 30*mm, 70*mm])
    firma_tabla.setStyle(TableStyle([
        ("ALIGN",  (0, 0), (-1, -1), "CENTER"),
        ("TOPPADDING", (0, 0), (-1, -1), 4),
    ]))
    story.append(firma_tabla)
    story.append(Spacer(1, 8*mm))

    # Hash
    story.append(HRFlowable(width="100%", thickness=0.5, color=GRIS_MED, spaceAfter=4))
    story.append(Paragraph(f"Hash de Operación: {r.hash_operacion}  |  Generado: {datetime.fromisoformat(r.timestamp).strftime('%d/%m/%Y %H:%M:%S')}", S["hash"]))
    story.append(Spacer(1, 4))

    # Disclaimer legal
    story.append(Paragraph(
        "AVISO LEGAL: Este informe ha sido generado mediante algoritmos de inteligencia artificial y métodos matemáticos "
        "reconocidos (Röss-Hödecke). Su valor es orientativo y no reemplaza la inspección física directa ni el criterio de un perito "
        "valuador colegiado. El valor estimado está sujeto a variaciones de mercado, condiciones macroeconómicas y la veracidad "
        "de los datos suministrados por el solicitante. ValuMetrics AI no asume responsabilidad legal por decisiones tomadas "
        "exclusivamente sobre la base de este documento.",
        S["disclaimer"]
    ))

    # ──────────────────────────────────────────────────────
    #  Build
    # ──────────────────────────────────────────────────────
    doc.build(story, onFirstPage=header_footer, onLaterPages=header_footer)
    return buffer.getvalue()
